import { useState, useEffect } from 'react';
import { BarCodeScanner } from 'expo-barcode-scanner';
import { View, Text, Button, Alert } from 'react-native';

const BarcodeScanner = ({ onProductFound }) => {
  const [hasPermission, setHasPermission] = useState(null);
  const [scanned, setScanned] = useState(false);

  useEffect(() => {
    (async () => {
      const { status } = await BarCodeScanner.requestPermissionsAsync();
      setHasPermission(status === 'granted');
    })();
  }, []);

  const handleBarCodeScanned = async ({ type, data }) => {
    setScanned(true);
    try {
      const product = await fetchProductByBarcode(data);
      if (product) {
        onProductFound(product);
      } else {
        Alert.alert('Produit non trouvé', 'Code-barres invalide');
      }
    } catch (error) {
      Alert.alert('Erreur', 'Vérifiez votre connexion');
    }
    setTimeout(() => setScanned(false), 2000);
  };

  if (hasPermission === null) return <Text>Demande de permission...</Text>;
  if (!hasPermission) return <Text>Permission caméra refusée</Text>;

  return (
    <View style={{ flex: 1 }}>
      <BarCodeScanner
        onBarCodeScanned={scanned ? undefined : handleBarCodeScanned}
        style={{ flex: 1 }}
      />
      {scanned && <Text>Scan terminé, recherche en cours...</Text>}
    </View>
  );
};
