import { useState } from 'react';
import { TouchableOpacity } from 'react-native';
import * as Speech from 'expo-speech';
import { useVoice } from 'expo-voice';

const VoiceSearch = ({ onSearch }) => {
  const [isListening, setIsListening] = useState(false);
  const { startListening, stopListening, transcripts } = useVoice();

  const speak = (text) => {
    Speech.speak(text, { language: 'fr', pitch: 1, rate: 0.9 });
  };

  const handleVoiceSearch = async () => {
    if (isListening) {
      stopListening();
      const lastTranscript = transcripts[transcripts.length - 1];
      if (lastTranscript) {
        speak(`Recherche de ${lastTranscript} en cours`);
        onSearch(lastTranscript);
      }
      setIsListening(false);
    } else {
      speak('Parlez maintenant');
      startListening();
      setIsListening(true);
      setTimeout(() => {
        if (isListening) {
          stopListening();
          setIsListening(false);
        }
      }, 5000);
    }
  };

  return (
    <TouchableOpacity onPress={handleVoiceSearch}>
      <Icon name={isListening ? 'microphone' : 'microphone-off'} size={30} />
    </TouchableOpacity>
  );
};
